import React, { useState } from 'react';
import {
    Box,
    Stepper,
    Step,
    StepLabel,
    Button,
    Typography,
    Container
} from '@mui/material';
import PhotoBookFormatSelector from './PhotoBookFormatSelector';

const steps = [
    'Выбор формата',
    'Добавление фотографий',
    'Создание страниц',
    'Предпросмотр'
];

const PhotoBookCreator = () => {
    const [activeStep, setActiveStep] = useState(0);
    const [selectedFormat, setSelectedFormat] = useState(null);

    const handleNext = () => {
        setActiveStep((prevStep) => prevStep + 1);
    };

    const handleBack = () => {
        setActiveStep((prevStep) => prevStep - 1);
    };

    const handleFormatSelect = (format) => {
        setSelectedFormat(format);
        handleNext();
    };

    const renderStepContent = (step) => {
        switch (step) {
            case 0:
                return <PhotoBookFormatSelector onFormatSelect={handleFormatSelect} />;
            case 1:
                return (
                    <Box sx={{ p: 4, textAlign: 'center' }}>
                        <Typography variant="h5" gutterBottom>
                            Добавление фотографий
                        </Typography>
                        <Typography variant="subtitle1" color="text.secondary" gutterBottom>
                            Выбранный формат: {selectedFormat?.size}
                        </Typography>
                        {/* Здесь будет компонент для загрузки фотографий */}
                    </Box>
                );
            case 2:
                return (
                    <Box sx={{ p: 4, textAlign: 'center' }}>
                        <Typography variant="h5" gutterBottom>
                            Создание страниц
                        </Typography>
                        {/* Здесь будет компонент для создания страниц */}
                    </Box>
                );
            case 3:
                return (
                    <Box sx={{ p: 4, textAlign: 'center' }}>
                        <Typography variant="h5" gutterBottom>
                            Предпросмотр фотокниги
                        </Typography>
                        {/* Здесь будет компонент предпросмотра */}
                    </Box>
                );
            default:
                return null;
        }
    };

    return (
        <Container maxWidth="lg">
            <Box sx={{ width: '100%', mt: 4 }}>
                <Stepper activeStep={activeStep}>
                    {steps.map((label) => (
                        <Step key={label}>
                            <StepLabel>{label}</StepLabel>
                        </Step>
                    ))}
                </Stepper>

                <Box sx={{ mt: 4, mb: 4 }}>
                    {renderStepContent(activeStep)}
                </Box>

                <Box sx={{ display: 'flex', justifyContent: 'space-between', pt: 2 }}>
                    <Button
                        variant="outlined"
                        disabled={activeStep === 0}
                        onClick={handleBack}
                    >
                        Назад
                    </Button>
                    <Button
                        variant="contained"
                        onClick={handleNext}
                        disabled={activeStep === 0 || (activeStep === steps.length - 1)}
                    >
                        {activeStep === steps.length - 1 ? 'Готово' : 'Далее'}
                    </Button>
                </Box>
            </Box>
        </Container>
    );
};

export default PhotoBookCreator;
